# Mixed-effects eye-tracking models for eye-emdm using brms
# Uses CSVs generated by analysis/choice_fixation_proportions.py (duration metric)

suppressPackageStartupMessages({
  library(brms)
  library(readr)
  library(dplyr)
  library(broom.mixed)
})

project_root <- getwd()
stats_dir <- file.path(project_root, "output", "eyegaze", "stats")

ensure_dir <- function(path) {
  if (!dir.exists(path)) dir.create(path, recursive = TRUE)
}

# brms sampling configuration
brms_chains <- 4
brms_iter <- 2000
brms_cores <- min(4, parallel::detectCores())
brms_seed <- 2026

save_model_outputs <- function(name, fit) {
  # Text summary
  summ <- summary(fit)
  summ_txt <- capture.output(summ)
  writeLines(summ_txt, file.path(stats_dir, paste0(name, "_summary.txt")))
  # Tidy coefficients
  tidy_df <- tryCatch({
    broom.mixed::tidy(fit, effects = "fixed")
  }, error = function(e) {
    NULL
  })
  if (!is.null(tidy_df)) {
    readr::write_csv(tidy_df, file.path(stats_dir, paste0(name, "_summary.csv")))
  }
}

ensure_dir(stats_dir)

# Helper to safely read CSV
read_csv_if_exists <- function(path) {
  if (file.exists(path)) {
    readr::read_csv(path, show_col_types = FALSE)
  } else {
    warning("File not found: ", path)
    NULL
  }
}

# ---------- 0) Relevant total fixation time vs chance (trial-level) ----------
# Based on trial-level relevant-only deltas produced by choice_fixation_proportions.py
# File: output/choice_fixation_relevant_trial_deltas_long_duration.csv

rel_long_path <- file.path(project_root, "output", "eyegaze", "stats", "choice_fixation_relevant_trial_deltas_long_duration.csv")

rel_long_df <- read_csv_if_exists(rel_long_path)

if (!is.null(rel_long_df)) {
  rel_long_df <- rel_long_df %>%
    mutate(subject = as.factor(subject))

  # Collapse over valence to get total relevant proportion per trial and its
  # deviation from chance. There are two rows per trial (rel_pos, rel_neg).
  rel_total_trial <- rel_long_df %>%
    group_by(subject, game, trial_number, decision_label) %>%
    summarise(
      prop_relevant = sum(prop, na.rm = TRUE),
      chance_relevant = sum(chance, na.rm = TRUE),
      delta_relevant = sum(delta_from_chance, na.rm = TRUE),
      .groups = "drop"
    ) %>%
    tidyr::drop_na(delta_relevant)

  if (nrow(rel_total_trial) > 0) {
    m0 <- brm(
      delta_relevant ~ 1 + (1 | subject),
      data = rel_total_trial,
      family = gaussian(),
      chains = brms_chains,
      iter = brms_iter,
      cores = brms_cores,
      seed = brms_seed
    )
    save_model_outputs("eye_relevant_total_delta_mixed", m0)
  }
}

# ---------- 1) Relevant-only relsign4: delta_from_chance ~ decision * valence ----------
# Mirrors: Trial-level Relevant-only MixedLM (delta ~ decision*valence + (1|subject))

if (!is.null(rel_long_df)) {
  d_rel_delta <- rel_long_df %>%
    mutate(
      subject = as.factor(subject),
      decision_label = as.factor(decision_label),
      valence_label = as.factor(valence_label)
    ) %>%
    tidyr::drop_na(delta_from_chance, decision_label, valence_label)

  if (nrow(d_rel_delta) > 0) {
    m_rel_delta <- brm(
      delta_from_chance ~ 1 + decision_label * valence_label + (1 + decision_label * valence_label | subject),
      data = d_rel_delta,
      family = gaussian(),
      chains = brms_chains,
      iter = brms_iter,
      cores = brms_cores,
      seed = brms_seed
    )
    save_model_outputs("eye_relsign4_relevant_delta_mixed", m_rel_delta)
  }
}

# ---------- 2) Relevant-only relsign4: prop ~ decision * valence ----------
# Mirrors: Trial-level Relevant-only MixedLM (prop ~ decision*valence + (1|subject))

if (!is.null(rel_long_df)) {
  d_rel_prop <- rel_long_df %>%
    mutate(
      subject = as.factor(subject),
      decision_label = as.factor(decision_label),
      valence_label = as.factor(valence_label)
    ) %>%
    tidyr::drop_na(prop, decision_label, valence_label)

  if (nrow(d_rel_prop) > 0) {
    m_rel_prop <- brm(
      prop ~ 1 + decision_label * valence_label + (1 + decision_label * valence_label | subject),
      data = d_rel_prop,
      family = gaussian(),
      chains = brms_chains,
      iter = brms_iter,
      cores = brms_cores,
      seed = brms_seed
    )
    save_model_outputs("eye_relsign4_relevant_prop_mixed", m_rel_prop)
  }
}

# ---------- 3) Irrelevant-only relsign4: delta_from_chance ~ decision * valence ----------
# Mirrors: Trial-level Irrelevant-only MixedLM (delta ~ decision*valence + (1|subject))

irr_long_path <- file.path(project_root, "output", "eyegaze", "stats", "choice_fixation_irrelevant_trial_deltas_long_duration.csv")

irr_long_df <- read_csv_if_exists(irr_long_path)

if (!is.null(irr_long_df)) {
