  if (nrow(d_irr_delta) > 0) {
    m_irr_delta <- brm(
      delta_from_chance ~ 1 + decision_label * valence_label + (1 + decision_label * valence_label | subject),
      data = d_irr_delta,
      family = gaussian(),
      chains = brms_chains,
      iter = brms_iter,
      cores = brms_cores,
      seed = brms_seed
    )
    save_model_outputs("eye_relsign4_irrelevant_delta_mixed", m_irr_delta)
  }
}

# ---------- 4) Irrelevant-only relsign4: prop ~ decision * valence ----------
# Mirrors: Trial-level Irrelevant-only MixedLM (prop ~ decision*valence + (1|subject))

if (!is.null(irr_long_df)) {
  d_irr_prop <- irr_long_df %>%
    mutate(
      subject = as.factor(subject),
      decision_label = as.factor(decision_label),
      valence_label = as.factor(valence_label)
    ) %>%
    tidyr::drop_na(prop, decision_label, valence_label)

  if (nrow(d_irr_prop) > 0) {
