# ---------- 5) Fixation duration ~ relevance * position (fixation-level) ----------
# Tests whether log fixation duration varies by relevance and fixation position
# Data: output/choice_fixations_clean_buffer_50.csv (one row per fixation)
# Position binned: 1-6 individually, 7+ collapsed to 7, treated as continuous

excluded_subjects <- c("107", "131")

fix_path <- file.path(project_root, "output", "choice_fixations_clean_buffer_50.csv")
fix_df <- read_csv_if_exists(fix_path)

if (!is.null(fix_df)) {
  fix_df <- fix_df %>%
    filter(!subject_id %in% excluded_subjects)

  n_subjects <- n_distinct(fix_df$subject_id)
  message("  Fixdur by position: N subjects = ", n_subjects)
  stopifnot(n_subjects == 41)

  fix_df <- fix_df %>%
    filter(!is.na(fixation_duration), fixation_duration > 0) %>%
    mutate(
      log_duration = log(fixation_duration),
      position_bin = pmin(fixation_count, 7),
      subject_id = as.factor(subject_id)
    )

  message("  N fixations = ", nrow(fix_df))

  m_fixdur_pos <- brm(
    log_duration ~ relevance * position_bin +
      (relevance * position_bin | subject_id),
    data = fix_df,
    family = gaussian(),
    chains = brms_chains,
    iter = brms_iter,
    cores = brms_cores,
    seed = brms_seed,
    control = list(adapt_delta = 0.95)
  )
  save_model_outputs("fixdur_by_position_human", m_fixdur_pos)
}

# ---------- 6) Proportion relevant fixated ~ position (subject-level) ----------
# Tests whether the proportion of fixations landing on relevant locations
# is above chance (0.5) and how it changes across fixation positions.
# Matches the y-axis of Figure 4C ("Prop. relevant fixated").
# Data: same fixation-level CSV as model 5, aggregated per subject x position.
# Position binned: 1-6 individually, 7+ collapsed to 7, treated as continuous.

if (!is.null(fix_df)) {
  # Aggregate to per-subject per-position proportion of relevant fixations
  fix_prop_df <- fix_df %>%
    group_by(subject_id, position_bin) %>%
    summarise(
      prop_relevant = mean(relevance, na.rm = TRUE),
      n_fixations = n(),
      .groups = "drop"
    ) %>%
    mutate(
      delta_chance = prop_relevant - 0.5
    )

  n_subj_prop <- n_distinct(fix_prop_df$subject_id)
  message("  Fixprop by position: N subjects = ", n_subj_prop)
  stopifnot(n_subj_prop == 41)
  message("  N subject x position obs = ", nrow(fix_prop_df))

  m_fixprop_pos <- brm(
    delta_chance ~ 1 + position_bin + (1 + position_bin | subject_id),
    data = fix_prop_df,
    family = gaussian(),
    chains = brms_chains,
    iter = brms_iter,
    cores = brms_cores,
    seed = brms_seed,
    control = list(adapt_delta = 0.95)
  )
  save_model_outputs("fixprop_by_position_human", m_fixprop_pos)
}

# ---------- 7) Valence × decision × position (3-way, chance-corrected) --------
# Tests whether reward valence (positive vs negative) differentiates gaze
# allocation across fixation positions differently for take vs leave decisions.
# Figure 4G-H.
#
# Computes chance-corrected proportions from fixation-level data joined with
# recalled rewards, matching the trial-level chance correction used in models
# 1-4 (chance = n_items_in_category / 6).
#
# Model: delta ~ dec_c * valence_c * position + (dec_c + valence_c + position | subject_id)
# Contrast coding:
#   dec_c:     take = +0.5, leave = -0.5
#   valence_c: positive = +0.5, negative = -0.5
#   position:  numeric (1-7, with 7+ collapsed)

message("\n---------- 7) Valence x decision x position (3-way, chance-corrected) ----------")

# Join fixation data with recalled rewards
item_vals_path <- file.path(project_root, "output", "behavior", "stats", "item_values_df.csv")
item_vals <- read_csv_if_exists(item_vals_path)

if (!is.null(fix_df) && !is.null(item_vals)) {
  # fix_df already filtered to N=41 and has position_bin from model 5

  item_vals <- item_vals %>%
    mutate(subject_id = as.character(subject)) %>%
    select(subject_id, game, image, recalled_value)

  fix_val <- fix_df %>%
    mutate(game = as.integer(game)) %>%
    left_join(item_vals, by = c("subject_id", "game", "image"))

  # Keep only relevant fixations with non-zero recalled reward
  fix_rel <- fix_val %>%
    filter(relevance == 1,
           !is.na(recalled_value),
           recalled_value != 0) %>%
    mutate(valence_label = ifelse(recalled_value > 0, "positive", "negative"))

  # Compute trial-level item counts for chance
  # For each trial, count how many relevant items have positive/negative recalled reward
  trial_items <- fix_val %>%
    filter(relevance == 1, !is.na(recalled_value), recalled_value != 0) %>%
    distinct(subject_id, game, trial_number, option, image, recalled_value) %>%
    mutate(valence_label = ifelse(recalled_value > 0, "positive", "negative")) %>%
    group_by(subject_id, game, trial_number, option, valence_label) %>%
    summarise(n_items = n(), .groups = "drop")

  # Chance = n_items_in_category / 6 (same as trial-level models)
  trial_chance <- trial_items %>%
    mutate(chance = n_items / 6)

  # For each trial × position_bin: count fixations by valence, compute proportion
  trial_pos_counts <- fix_rel %>%
    group_by(subject_id, game, trial_number, option, position_bin, valence_label) %>%
    summarise(n_fix = n(), .groups = "drop")

  # Total fixations at each trial × position (all items, not just relevant)
  trial_pos_total <- fix_df %>%
    filter(!is.na(fixation_duration), fixation_duration > 0) %>%
    group_by(subject_id, game, trial_number, option, position_bin) %>%
    summarise(n_total = n(), .groups = "drop")

  # Build full grid: trial × position × valence
  grid <- tidyr::expand_grid(
    trial_pos_total %>% select(subject_id, game, trial_number, option, position_bin),
    valence_label = c("positive", "negative")
  ) %>%
    distinct()

  trial_pos_props <- grid %>%
    left_join(trial_pos_total,
              by = c("subject_id", "game", "trial_number", "option", "position_bin")) %>%
    left_join(trial_pos_counts,
              by = c("subject_id", "game", "trial_number", "option", "position_bin", "valence_label")) %>%
    left_join(trial_chance,
              by = c("subject_id", "game", "trial_number", "option", "valence_label")) %>%
    mutate(
      n_fix = tidyr::replace_na(n_fix, 0),
      chance = tidyr::replace_na(chance, 0),
      prop = n_fix / n_total,
      delta = prop - chance
    )

  # Add decision info from fixation data
  decision_info <- fix_df %>%
    distinct(subject_id, game, trial_number, option, choice)

  trial_pos_props <- trial_pos_props %>%
    left_join(decision_info,
              by = c("subject_id", "game", "trial_number", "option")) %>%
    filter(!is.na(choice))

  # Aggregate to subject × position × decision × valence
  subj_pos <- trial_pos_props %>%
    mutate(decision = ifelse(choice == 1, "take", "leave")) %>%
    group_by(subject_id, position_bin, decision, valence_label) %>%
    summarise(delta = mean(delta, na.rm = TRUE), .groups = "drop")

  n_subj_gh <- n_distinct(subj_pos$subject_id)
  message("  N subjects = ", n_subj_gh)
  stopifnot(n_subj_gh == 41)

  d_long <- subj_pos %>%
    mutate(
      dec_c = ifelse(decision == "take", 0.5, -0.5),
      valence_c = ifelse(valence_label == "positive", 0.5, -0.5),
      position = position_bin,
      subject_id = factor(subject_id)
    )

  message("  Positions: ", paste(sort(unique(d_long$position)), collapse = ", "))
  message("  Observations: ", nrow(d_long),
          "  |  Subjects: ", n_distinct(d_long$subject_id))

  m_valence_pos <- brm(
    delta ~ dec_c * valence_c * position +
      (dec_c + valence_c + position | subject_id),
    data = d_long,
    family = gaussian(),
    chains = brms_chains,
    iter = brms_iter,
    cores = brms_cores,
    seed = brms_seed,
    control = list(adapt_delta = 0.95)
  )
  save_model_outputs("valence_by_position_human", m_valence_pos)
} else {
  message("  SKIPPED model 7: fixation data or item_values_df.csv not found")
}

message("Eye-tracking mixed-effects model summaries saved to ", stats_dir)
